<?php
require_once __DIR__.'/functions.php';require_login();$id=current_user_id();
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();if(!$id){flash('Esta cuenta proviene de .env. Cambia ADMIN_PASSWORD_HASH en ese archivo o crea un administrador MySQL.','error');redirect('/account.php');}$current=(string)($_POST['current_password']??'');$new=(string)($_POST['new_password']??'');$confirm=(string)($_POST['confirm_password']??'');$stmt=db()->prepare('SELECT password_hash FROM users WHERE id=? AND active=1');$stmt->execute([$id]);$hash=(string)$stmt->fetchColumn();if(!$hash||!password_verify($current,$hash)){flash('La contraseña actual es incorrecta.','error');}elseif(strlen($new)<12){flash('La nueva contraseña debe tener al menos 12 caracteres.','error');}elseif($new!==$confirm){flash('Las contraseñas nuevas no coinciden.','error');}elseif(password_verify($new,$hash)){flash('La nueva contraseña debe ser diferente.','error');}else{db()->prepare('UPDATE users SET password_hash=? WHERE id=?')->execute([password_hash($new,PASSWORD_DEFAULT),$id]);session_regenerate_id(true);$_SESSION['csrf']=bin2hex(random_bytes(32));flash('Contraseña administrativa actualizada.');redirect('/account.php');}}
render_header('Mi cuenta',['robots'=>'noindex,nofollow']);?><section class="panel narrow"><h1>Mi cuenta</h1><p class="muted">Cambia la contraseña con la que accedes al panel.</p><?php if(!$id):?><div class="flash error">Tu acceso actual proviene del archivo .env y no puede modificarse desde MySQL.</div><?php else:?><p><a class="button" href="/staff-profile.php">Editar mi perfil público</a></p><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><label>Contraseña actual<input type="password" name="current_password" autocomplete="current-password" required></label><label>Nueva contraseña<input type="password" name="new_password" minlength="12" autocomplete="new-password" required></label><label>Confirmar nueva contraseña<input type="password" name="confirm_password" minlength="12" autocomplete="new-password" required></label><button class="button">Cambiar mi contraseña</button></form><?php endif;?></section><?php render_footer();
